#include <bits/stdc++.h>
using namespace std;
long long b[55][55];
int n,m;
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)cin>>b[i][j];
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            int maxn=0;
            for(int x=1;x<=n;x++)
                for(int y=1;y<=m;y++)
                    if((i!=x || y!=j) && b[i][j]==b[x][y])
                        maxn=max(maxn,(i-x)*(i-x)+(j-y)*(j-y));
            cout<<maxn<<' ';
        }
        cout<<endl;
    }
    return 0;
}
